#!/usr/bin/env node
/**
 * generate-sdd-assets.mjs
 *
 * Packages the SDD framework files from the repository root into a TypeScript
 * module so the Specter binary can install SDD into any project without
 * reaching out to the network.
 *
 * Run manually after changing SDD files:
 *   node scripts/generate-sdd-assets.mjs
 *
 * The generated file is checked in so builds remain reproducible.
 */

import { mkdir, readdir, readFile, stat, writeFile } from 'node:fs/promises';
import { dirname, join, relative } from 'node:path';

const REPO_ROOT = new URL('..', import.meta.url).pathname;
const SDD_ROOT = join(REPO_ROOT, 'sdd');
const SCRIPTS_ROOT = join(REPO_ROOT, 'scripts');
const OUTPUT_FILE = join(
  REPO_ROOT,
  'packages/agent-core/src/tools/builtin/sdd/sdd-assets.ts',
);

const ROOT_FILES = [
  // The root AGENTS.md belongs to the Specter repo itself; projects receiving
  // SDD keep their own AGENTS.md or get the generic SDD one in sdd/AGENTS.md.
  'CLAUDE.md',
];

const SDD_GLOBS = [
  'README.md',
  'workflow.md',
  'architecture.md',
  'conventions.md',
  'quality-gates.md',
  'testing.md',
  'security.md',
  'delivery.md',
  'troubleshooting.md',
  'product.md',
  'tech-stack.md',
  'init-project.sh',
  'templates/**/*.md',
  'decisions/**/*.md',
];

const SCRIPT_FILES = [];

const EMPTY_DIRS = ['sdd/features', 'sdd/decisions'];

async function* walk(dir) {
  const entries = await readdir(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = join(dir, entry.name);
    if (entry.isDirectory()) {
      yield* walk(fullPath);
    } else if (entry.isFile()) {
      yield fullPath;
    }
  }
}

async function collectFiles() {
  const files = [];

  for (const name of ROOT_FILES) {
    const path = join(REPO_ROOT, name);
    try {
      const s = await stat(path);
      if (s.isFile()) files.push(path);
    } catch {
      console.warn(`Missing root file: ${name}`);
    }
  }

  for await (const path of walk(SDD_ROOT)) {
    const rel = relative(SDD_ROOT, path);
    const isTemplate = rel.startsWith('templates/');
    const isDecision = rel.startsWith('decisions/');
    const isTopLevelDoc = SDD_GLOBS.some((g) => {
      if (g.endsWith('**/*.md')) {
        const prefix = g.slice(0, -'**/*.md'.length);
        return rel.startsWith(prefix) && rel.endsWith('.md');
      }
      return rel === g;
    });
    if (isTopLevelDoc || isTemplate || isDecision) {
      files.push(path);
    }
  }

  for (const name of SCRIPT_FILES) {
    const path = join(SCRIPTS_ROOT, name);
    try {
      const s = await stat(path);
      if (s.isFile()) files.push(path);
    } catch {
      console.warn(`Missing script file: ${name}`);
    }
  }

  // Projects receiving SDD get a generic root AGENTS.md copied from sdd/AGENTS.md.
  const genericAgentsPath = join(SDD_ROOT, 'AGENTS.md');
  try {
    const s = await stat(genericAgentsPath);
    if (s.isFile()) files.push(genericAgentsPath);
  } catch {
    console.warn('Missing generic SDD AGENTS.md template: sdd/AGENTS.md');
  }

  files.sort((a, b) => a.localeCompare(b));
  return files;
}

function toPosixPath(path) {
  return path.replace(/\\/g, '/');
}

function toAssetPath(absolutePath) {
  const rel = relative(REPO_ROOT, absolutePath);
  return toPosixPath(rel);
}

const ASSET_PATH_RENAMES = {
  'sdd/AGENTS.md': 'AGENTS.md',
  'sdd/init-project.sh': 'init.sh',
};

async function main() {
  const files = await collectFiles();
  const assets = [];

  for (const path of files) {
    const content = await readFile(path, 'utf-8');
    const relPath = toAssetPath(path);
    const assetPath = ASSET_PATH_RENAMES[relPath] ?? relPath;
    assets.push({
      path: assetPath,
      content,
      executable: path.endsWith('.sh'),
    });
  }

  const lines = [
    '// Auto-generated by scripts/generate-sdd-assets.mjs',
    '// Do not edit manually.',
    '',
    'export interface SddAsset {',
    "  readonly path: string;",
    "  readonly content: string;",
    "  readonly executable?: boolean;",
    '}',
    '',
    'export const SDD_ASSETS: readonly SddAsset[] = [',
  ];

  for (const asset of assets) {
    const escaped = asset.content
      .replace(/\\/g, '\\\\')
      .replace(/'/g, "\\'")
      .replace(/\n/g, '\\n')
      .replace(/\r/g, '\\r');
    const execFlag = asset.executable ? ', executable: true' : '';
    lines.push(`  { path: '${asset.path}', content: '${escaped}'${execFlag} },`);
  }

  lines.push('];', '');
  lines.push('export const SDD_EMPTY_DIRS: readonly string[] = [',);
  for (const dir of EMPTY_DIRS) {
    lines.push(`  '${dir}',`);
  }
  lines.push('];', '');

  await mkdir(dirname(OUTPUT_FILE), { recursive: true });
  await writeFile(OUTPUT_FILE, lines.join('\n'), 'utf-8');
  console.log(`Generated ${OUTPUT_FILE} with ${assets.length} assets.`);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
